import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { apiClient, authService } from "@/App";
import { toast } from "sonner";
import { Building2, Upload, Image as ImageIcon } from "lucide-react";

const SchoolProfilePage = () => {
  const [school, setSchool] = useState(null);
  const [loading, setLoading] = useState(true);
  const [editing, setEditing] = useState(false);
  const [logoPreview, setLogoPreview] = useState(null);

  const [formData, setFormData] = useState({
    name: "",
    address: "",
    phone: "",
    email: "",
    school_type: "",
    logo_url: "",
    motto: "",
    vision: "",
    mission: "",
    principal_name: "",
    website: "",
    established_year: ""
  });

  const user = authService.getUser();

  useEffect(() => {
    fetchSchoolProfile();
  }, []);

  const fetchSchoolProfile = async () => {
    try {
      if (user?.school_id) {
        const response = await apiClient.get(`/schools/${user.school_id}`);
        setSchool(response.data);

        setFormData({
          name: response.data.name || "",
          address: response.data.address || "",
          phone: response.data.phone || "",
          email: response.data.email || "",
          school_type: response.data.school_type || "",
          logo_url: response.data.logo_url || "",
          motto: response.data.motto || "",
          vision: response.data.vision || "",
          mission: response.data.mission || "",
          principal_name: response.data.principal_name || "",
          website: response.data.website || "",
          established_year: response.data.established_year || ""
        });

        if (response.data.logo_url) {
          setLogoPreview(response.data.logo_url);
        }
      }
    } catch (error) {
      toast.error("Failed to fetch school profile");
    } finally {
      setLoading(false);
    }
  };

  const handleLogoUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    if (file.size > 5 * 1024 * 1024) {
      toast.error("Logo size should be less than 5MB");
      return;
    }

    const reader = new FileReader();
    reader.onloadend = () => {
      setLogoPreview(reader.result);
      setFormData({ ...formData, logo_url: reader.result });
    };
    reader.readAsDataURL(file);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      if (!user?.school_id) {
        const response = await apiClient.post("/auth/register-school", {
          ...formData,
          admin_name: user?.full_name || "Admin",
          admin_email: user?.email,
          admin_password: "12345678",
          admin_phone: user?.phone || ""
        });

        toast.success("School registered successfully!");
        window.location.href = `/s/${response.data.school_slug}`;
        return;
      }

      const cleanData = Object.fromEntries(
        Object.entries(formData).filter(([_, v]) => v !== "")
      );

      await apiClient.patch(`/schools/${user.school_id}`, cleanData);

      toast.success("School profile updated successfully");
      setEditing(false);
      fetchSchoolProfile();

    } catch (error) {
      toast.error(error.response?.data?.detail || "Operation failed");
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary mx-auto"></div>
          <p className="mt-4">Loading...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">

      {/* HEADER */}
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-bold">School Profile</h2>
        </div>

        {!editing ? (
          <Button onClick={() => setEditing(true)}>
            Edit Profile
          </Button>
        ) : (
          <Button variant="outline" onClick={() => setEditing(false)}>
            Cancel
          </Button>
        )}
      </div>

      {/* VIEW MODE */}
      {!editing && (
        <Card>
          <CardContent className="p-10 text-center space-y-6">

            {logoPreview ? (
              <img src={logoPreview} className="w-32 h-32 mx-auto" />
            ) : (
              <Building2 className="w-20 h-20 mx-auto" />
            )}

            <h1 className="text-4xl font-bold">{formData.name || "School Name"}</h1>

            <p className="text-gray-500 italic">{formData.motto}</p>

            <p>{formData.address}</p>
            <p>{formData.phone}</p>
            <p>{formData.email}</p>

            {!user?.school_id && (
              <Button onClick={() => setEditing(true)} className="mt-6">
                Complete School Setup
              </Button>
            )}

          </CardContent>
        </Card>
      )}

      {/* EDIT MODE */}
      {editing && (
        <form onSubmit={handleSubmit} className="space-y-6">

          <Card>
            <CardHeader>
              <CardTitle>Logo</CardTitle>
            </CardHeader>
            <CardContent>
              <Input type="file" onChange={handleLogoUpload} />
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Basic Info</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">

              <Input
                placeholder="School Name"
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                required
              />

              <Input
                placeholder="Phone"
                value={formData.phone}
                onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
                required
              />

              <Input
                placeholder="Email"
                value={formData.email}
                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                required
              />

              <Textarea
                placeholder="Address"
                value={formData.address}
                onChange={(e) => setFormData({ ...formData, address: e.target.value })}
              />

              <Input
                placeholder="Motto"
                value={formData.motto}
                onChange={(e) => setFormData({ ...formData, motto: e.target.value })}
              />

            </CardContent>
          </Card>

          <Button type="submit" className="w-full bg-emerald-600">
            Submit & Open School Portal
          </Button>

        </form>
      )}

    </div>
  );
};

export default SchoolProfilePage;
